import React from 'react';

const SoftwareSolutions = () => {
  return (
    <div className="pt-24 min-h-screen bg-blue-900 text-white">
      <div className="max-w-7xl mx-auto px-4 py-16 text-center">
        <h1 className="text-4xl font-bold mb-6">Innovative Software Solutions</h1>
        <p className="text-xl text-blue-200 mb-12">Building scalable enterprise systems for modern businesses.</p>
        <div className="grid md:grid-cols-2 gap-10">
          <div className="p-6 border border-blue-700 rounded-lg">
            <h2 className="text-2xl font-semibold mb-4">Custom ERP Systems</h2>
            <p className="text-blue-100">Tailored resource planning for large-scale operations.</p>
          </div>
          <div className="p-6 border border-blue-700 rounded-lg">
            <h2 className="text-2xl font-semibold mb-4">AI-Driven Analytics</h2>
            <p className="text-blue-100">Smart data processing for better business decisions.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SoftwareSolutions;
